/**
 * @name ZipEntry/TarEntry name flowing to File constructor without path traversal check
 * @description Archive entry names used directly in file construction can enable path traversal (Zip Slip)
 * @kind path-problem
 * @problem.severity error
 * @id java/zip-slip-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module ZipSlipConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // ZipEntry.getName()
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.commons.compress.archivers", "ArchiveEntry") and
      source.asExpr() = mc
    )
    or
    // TarArchiveEntry.getName()
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.commons.compress.archivers.tar", "TarArchiveEntry") and
      source.asExpr() = mc
    )
    or
    // java.util.zip.ZipEntry.getName()
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.util.zip", "ZipEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // new File(...)
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get(...)
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // FileOutputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module ZipSlipFlow = TaintTracking::Global<ZipSlipConfig>;
import ZipSlipFlow::PathGraph

from ZipSlipFlow::PathNode source, ZipSlipFlow::PathNode sink
where ZipSlipFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Archive entry name flows to file operation, potential path traversal (Zip Slip) from $@.", source.getNode(), "archive entry name"

