/**
 * @name Tar/Zip entry name flows to File in extraction methods
 * @description Archive entry name flows to File construction in extraction code - Zip Slip vulnerability
 * @kind path-problem
 * @problem.severity error
 * @id java/zip-slip-extraction-v2
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module ZipSlipV2Config implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Any getName() call on any type - broad to catch all entry names
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      source.asExpr() = mc
    )
    or
    // getEntryName() patterns
    exists(MethodCall mc |
      mc.getMethod().hasName("getEntryName") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // new File(...) specifically in extraction-related methods
    exists(ClassInstanceExpr ce, Callable m |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument() and
      m = ce.getEnclosingCallable() and
      (
        m.getName().matches("%extract%") or
        m.getName().matches("%unpack%") or
        m.getName().matches("%decompress%") or
        m.getName() = "execute" or
        m.getDeclaringType().getName().matches("%UnArchiver%") or
        m.getDeclaringType().getName().matches("%Unarchiver%")
      )
    )
  }
}

