/**
 * @name TarUnArchiver direct file construction bypassing extractFile check
 * @description TarUnArchiver constructs File objects from entry names outside of the canonical path checked extractFile method
 * @kind path-problem
 * @problem.severity error
 * @id java/tar-direct-file-no-check
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module TarDirectFileConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // getName() calls in TarUnArchiver or its execute method
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      source.asExpr() = mc and
      mc.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.codehaus.plexus.archiver.tar%")
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File construction anywhere in tar package
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument() and
      ce.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.codehaus.plexus.archiver.tar%")
    )
    or
    // Flows to extractFile call
    exists(MethodCall mc |
      mc.getMethod().hasName("extractFile") and
      sink.asExpr() = mc.getAnArgument() and
      mc.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.codehaus.plexus.archiver.tar%")
    )
    or
    // Flows to symlink creation
    exists(MethodCall mc |
      (mc.getMethod().hasName("createSymbolicLink") or mc.getMethod().hasName("createSymlink")) and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

