/**
 * @name Symlink target path traversal in archive extraction
 * @description Archive entry symlink targets flow to file operations without path validation
 * @kind path-problem
 * @problem.severity error
 * @id java/archive-symlink-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module SymlinkTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // getLinkName() for symlink targets in tar entries
    exists(MethodCall mc |
      mc.getMethod().hasName("getLinkName") and
      source.asExpr() = mc
    )
    or
    // getName() in the context of symlink resource creation  
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      source.asExpr() = mc and
      mc.getEnclosingCallable().getDeclaringType().getName().matches("%Symlink%")
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File construction
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // createSymbolicLink / Path.of for symlink creation
    exists(MethodCall mc |
      (mc.getMethod().hasName("createSymbolicLink") or
       mc.getMethod().hasName("createLink") or
       mc.getMethod().hasName("createSymlink")) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Paths.get()
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

