/**
 * @name Symlink target in extractFile bypasses canonical path check
 * @description The symlink target (linkName parameter) flows to File construction at line 371 without canonical path validation
 * @kind path-problem
 * @problem.severity error
 * @id java/symlink-target-no-canonical-check
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module SymlinkTargetConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // getLinkName() on TarArchiveEntry 
    exists(MethodCall mc |
      mc.getMethod().hasName("getLinkName") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File construction in AbstractUnArchiver
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument() and
      ce.getEnclosingCallable().getDeclaringType().getASupertype*().hasQualifiedName("org.codehaus.plexus.archiver", "AbstractUnArchiver")
    )
    or
    // createSymbolicLink calls
    exists(MethodCall mc |
      mc.getMethod().hasName("createSymbolicLink") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Path.of / Paths.get for symlink destination
    exists(MethodCall mc |
      (mc.getMethod().hasName("get") and mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths")) or
      (mc.getMethod().hasName("of") and mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Path")) |
      sink.asExpr() = mc.getAnArgument()
    )
  }

  // Would be blocked if canonical file check is done before
  predicate isBarrier(DataFlow::Node node) {
    exists(MethodCall mc |
      (mc.getMethod().hasName("getCanonicalPath") or
       mc.getMethod().hasName("getCanonicalFile") or
       mc.getMethod().hasName("toRealPath")) and
      DataFlow::localFlow(node, DataFlow::exprNode(mc.getQualifier()))
    )
  }
}

